import { Hound, InMemoryStorage } from 'hound/';

const hound = Hound.create({
  db: new InMemoryStorage(),
});

import { Hound } from 'hound/';
import { connect } from 'npm:ioredis';

const redis = new connect(Deno.env.get('REDIS_URL'));

const hound = Hound.create({ db: redis });

import { Hound, DenoKvStorage } from 'hound/';

const kv = await Deno.openKv();
const hound = Hound.create({
  db: new DenoKvStorage(kv),
});
